                        borderRadius: '50px',
                        fontSize: '0.8rem',
                        marginBottom: '1rem'
                      }}>
                        🎫 {review.tour}
                        {review.guide && <span style={{ marginLeft: '1rem' }}>👤 {review.guide}</span>}
                      </div>

                      <div className="review-content">
                        <h5 className="review-title" style={{ fontSize: '1.1rem', fontWeight: 600 }}>
                          {review.title}
                        </h5>
                        <p className="review-comment" style={{ fontSize: '0.9rem', color: '#495057' }}>
                          "{review.comment}"
                        </p>
                        <p className="review-date" style={{ fontSize: '0.75rem', color: '#6c757d' }}>
                          📅 {new Date(review.createdAt).toLocaleDateString()}
                        </p>
                      </div>

                      {/* Approve/Reject Buttons - Only show for pending reviews */}
                      <div className="review-actions" style={{
                        display: 'flex',
                        gap: '0.75rem',
                        marginTop: '1.25rem'
                      }}>
                        {!review.isApproved ? (
                          <>
                            <button
                              className="btn-success"
                              onClick={() => handleApproveReview(review._id)}
                              style={{
                                flex: 1,
                                background: 'linear-gradient(135deg, #17b794, #0f8a6d)',
                                color: 'white',
                                border: 'none',
                                padding: '0.6rem',
                                borderRadius: '12px',
                                fontWeight: 600,
                                cursor: 'pointer'
                              }}
                            >
                              ✅ Approve
                            </button>
                            <button
                              className="btn-danger"
                              onClick={() => handleRejectReview(review._id)}
                              style={{
                                flex: 1,
                                background: 'linear-gradient(135deg, #ff6b35, #e8594c)',
                                color: 'white',
                                border: 'none',
                                padding: '0.6rem',
                                borderRadius: '12px',
                                fontWeight: 600,
                                cursor: 'pointer'
                              }}
                            >
                              ❌ Reject
                            </button>
                          </>
                        ) : (
                          <span style={{
                            width: '100%',
                            textAlign: 'center',
                            padding: '0.6rem',
                            background: '#d4edda',
                            color: '#155724',
                            borderRadius: '12px',
                            fontWeight: 600
                          }}>
                            ✓ Approved
                          </span>
                        )}
                      </div>
                    </div>
                  ))}

                  {filteredReviews.length === 0 && (
                    <div className="empty-state">
                      <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                        <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"></polygon>
                      </svg>
                      <h3>No reviews found</h3>
                      <p>There are no {reviewFilter !== 'all' ? reviewFilter : ''} reviews to display.</p>
                    </div>
                  )}
                </div>
              </div>
            )}
          </main>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
